What does this program print?

```cpp
#include <iostream>

struct Vec {
    int x{}, y{};
};

Vec operator+(const Vec& a, const Vec& b) {
    return Vec{a.x + b.x, a.y + b.y};
}

int main() {
    Vec u{3, 5};
    Vec v{1, 2};
    Vec w = u + v;
    std::cout << w.x << " " << w.y << "\n";
    return 0;
}
```

